"use strict";exports.toFriendlyTime=function(t,e=!1){const r=new Date,n=new Date(t);if(n>r+3e4)return"未来";const $=(new Date).setHours(0,0,0,0),o=e?n.getHours()>=12?"下午 ":"上午 ":"",a=e?n.getHours()%12:n.getHours(),s=n.getMinutes().toString().padStart(2,"0");if(t>=$){const t=Math.floor((r-n)/1e3);if(t<60)return"刚刚";if(t<3600){return`${Math.floor(t/60)}分钟前`}if(t<7200){const e=Math.floor(t/3600),r=Math.floor((t-60*e*60)/60);return r?`${e}小时 ${r}分钟前`:`${e}小时前`}return`${o}${a}:${s}`}if(t>=$-864e5)return`昨天 ${o}${a}:${s}`;if(t>=$-1728e5)return`前天 ${o}${a}:${s}`;const u=n.getFullYear(),i=(n.getMonth()+1).toString().padStart(2,"0"),f=n.getDate().toString().padStart(2,"0");if(t>=(new Date).setMonth(0,0)){const e=new Date;e.setDate(e.getDate()-e.getDay());if(t>=e.setHours(0,0,0,0)){return`${["周日","周一","周二","周三","周四","周五","周六"][n.getDay()]} ${o}${a}:${s}`}return`${i}/${f} ${o}${a}:${s}`}return`${u}/${i}/${f} ${o}${a}:${s}`};
